mapper.select:
SELECT * FROM resume
WHERE user_id = #{userId}
ORDER BY created_at DESC

SELECT * FROM resume
WHERE cycle_id = #{cycleId}
ORDER BY created_at DESC

SELECT r.* FROM resume r
LEFT JOIN user u ON r.user_id = u.user_id


        AND u.name LIKE CONCAT('%', #{name}, '%')


        AND u.major LIKE CONCAT('%', #{major}, '%')



        AND EXISTS (
            SELECT 1 FROM resume_field_value rv
            JOIN resume_field_definition rf ON rv.field_id = rf.field_id
            WHERE rv.resume_id = r.resume_id
            AND rf.field_label = '期望部门'
            AND rv.field_value LIKE CONCAT('%', #{expectedDepartment}, '%')
        )


        AND r.cycle_id = #{cycleId}


        AND r.status IN

            #{item}



ORDER BY


        ${sortBy}


        r.created_at




        ${sortOrder}


        DESC


LIMIT #{offset}, #{limit}
